# --- plot helper (hidden) — English score for every Caesar shift ---
# Each bar is the student's OWN english_score of their caesar_decrypt at that
# shift. Falls back to a built-in scorer until those work.
__COMMON = {"the", "and", "you", "that", "was", "for", "are", "with", "his", "they", "this", "have", "from", "one", "had", "not", "but", "what", "all", "when", "your", "can", "there", "she", "how", "their", "will", "about", "out", "them", "then", "some", "her", "would", "make", "like", "him", "into", "time", "has", "two", "more", "see", "way", "could", "who", "now", "did", "get", "come", "is", "to", "of", "in", "it", "he", "on", "as", "at", "be", "we", "or", "by", "a", "an", "my", "so", "up"}

def __decrypt_ref(msg, n):
    return "".join(chr((ord(c) - 97 - n) % 26 + 97) if "a" <= c <= "z" else c for c in msg)

def __score_ref(text):
    return sum(1 for w in text.split() if w in __COMMON)

def __plot(cipher):
    try:
        pts = [[n, english_score(caesar_decrypt(cipher, n))] for n in range(26)]   # <- STUDENT's functions
        if len(pts) == 26 and any(p[1] for p in pts):
            return [{"name": "English score for each shift (your code)", "points": pts, "highlight": True}]
    except Exception:
        pass
    pts = [[n, __score_ref(__decrypt_ref(cipher, n))] for n in range(26)]
    return [{"name": "English score for each shift", "points": pts, "highlight": True}]
